    fn test_entry(id: &str) -> MountEntry {
        MountEntry {
            id: id.to_string(),
            url: "http://localhost:9000".to_string(),
            mountpoint: PathBuf::from(format!("/mnt/{id}")),
            read_only: false,
            username: Some("admin".to_string()),
